import type { ZeroAPISpec } from '../../types/spec.js'

export interface FlyOptions {
  region?: string
  port?: number
  memory?: '256mb' | '512mb' | '1gb' | '2gb'
  cpus?: 1 | 2 | 4
  minMachines?: number
  nodeVersion?: string
}

/**
 * Generates a fly.toml configuration for deploying on Fly.io.
 */
export function generateFlyConfig(spec: ZeroAPISpec, options: FlyOptions = {}): string {
  const {
    region = 'cdg',
    port = 3000,
    memory = '256mb',
    cpus = 1,
    minMachines = 0,
    nodeVersion = '22',
  } = options

  const appName = spec.name.toLowerCase().replace(/[^a-z0-9-]/g, '-')

  return `# Generated by @ludagg/zeroapi-runtime for "${spec.name}" v${spec.version}
# Deploy: https://fly.io

app = "${appName}"
primary_region = "${region}"

[build]
  [build.args]
    NODE_VERSION = "${nodeVersion}"

[env]
  NODE_ENV = "production"
  PORT = "${port}"

[http_service]
  internal_port = ${port}
  force_https = true
  auto_stop_machines = true
  auto_start_machines = true
  min_machines_running = ${minMachines}

  [[http_service.checks]]
  grace_period = "10s"
  interval = "30s"
  method = "GET"
  timeout = "5s"
  path = "/health"

[[vm]]
  cpus = ${cpus}
  memory = "${memory}"
`
}

/**
 * Returns a Markdown "Deploy on Fly.io" badge for the given app name.
 */
export function getFlyDeployButton(appName: string): string {
  return `[![Deploy on Fly.io](https://fly.io/badges/deployed.svg)](https://fly.io/apps/${appName})`
}
